import{_ as t,o as r,c as s,S as n}from"./chunks/framework.DZlzLDBr.js";const h=JSON.parse('{"title":"Suspending Cards","description":"","frontmatter":{},"headers":[],"relativePath":"Suspending-Cards.md","filePath":"Suspending-Cards.md","lastUpdated":null}'),a={name:"Suspending-Cards.md"};function o(d,e,i,u,l,c){return r(),s("div",null,[...e[0]||(e[0]=[n('<h1 id="suspending-cards" tabindex="-1">Suspending Cards <a class="header-anchor" href="#suspending-cards" aria-label="Permalink to &quot;Suspending Cards&quot;">​</a></h1><p>Last modified: 13/02/2026</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Suspending removes a card from study sessions until you unsuspend it.</p><p>The card is kept in your collection, but it is not shown for review.</p><p>Unlike burying, suspension does not reset automatically.</p><h2 id="how-to-suspend-a-card" tabindex="-1">How to suspend a card <a class="header-anchor" href="#how-to-suspend-a-card" aria-label="Permalink to &quot;How to suspend a card&quot;">​</a></h2><h3 id="during-a-study-session" tabindex="-1">During a study session <a class="header-anchor" href="#during-a-study-session" aria-label="Permalink to &quot;During a study session&quot;">​</a></h3><ul><li>Press <strong><code>S</code></strong> on your keyboard, or</li><li>Open the <strong>More menu</strong> (press <code>M</code> or tap <strong>⋮</strong>) and choose <strong>Suspend</strong>.</li></ul><h3 id="from-the-card-browser" tabindex="-1">From the Card Browser <a class="header-anchor" href="#from-the-card-browser" aria-label="Permalink to &quot;From the Card Browser&quot;">​</a></h3><ol><li>Open the <a href="./Card-Browser">Card Browser</a>.</li><li>Select one or more cards.</li><li>Click the <strong>Suspend</strong> button in the bulk actions bar.</li></ol><p>To unsuspend, select suspended cards and click <strong>Unsuspend</strong>.</p><h2 id="finding-suspended-cards" tabindex="-1">Finding suspended cards <a class="header-anchor" href="#finding-suspended-cards" aria-label="Permalink to &quot;Finding suspended cards&quot;">​</a></h2><p>In <a href="./Card-Browser">Card Browser</a>, filter by <strong>Stage → Suspended</strong>.</p><h2 id="when-to-suspend" tabindex="-1">When to suspend <a class="header-anchor" href="#when-to-suspend" aria-label="Permalink to &quot;When to suspend&quot;">​</a></h2><p>Suspending is useful when:</p><ul><li>A card is outdated or incorrect and you want to stop reviewing it until you fix the content.</li><li>You&#39;re studying a subset of material (e.g. only certain chapters) and want to temporarily exclude other cards.</li><li>A card is a leech (you keep forgetting it) and you need to rewrite it before continuing.</li></ul><h2 id="suspending-vs-burying" tabindex="-1">Suspending vs burying <a class="header-anchor" href="#suspending-vs-burying" aria-label="Permalink to &quot;Suspending vs burying&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Bury</th><th>Suspend</th></tr></thead><tbody><tr><td><strong>Duration</strong></td><td>Until midnight (automatic reset)</td><td>Until you manually unsuspend</td></tr><tr><td><strong>Best for</strong></td><td>Skipping a card for the rest of the day</td><td>Removing a card from reviews long-term</td></tr><tr><td><strong>Scheduling impact</strong></td><td>None</td><td>None</td></tr><tr><td><strong>How to reverse</strong></td><td>Automatic (next day)</td><td>Manual (unsuspend in browser or during study)</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Use <strong>Bury</strong> for &quot;I&#39;ll try again tomorrow&quot; and <strong>Suspend</strong> for &quot;I need to fix this card first.&quot;</p></div>',20)])])}const g=t(a,[["render",o]]);export{h as __pageData,g as default};
